def process(items):
    result = {}
    for item in items:
        key = item.get('type', 'unknown')
        if key not in result:
            result[key] = []
        result[key].append(item['value'])
    return {k: sorted(v) for k, v in result.items()}

Translate this JavaScript Promise chain to async/await syntax, preserving exact error handling semantics:
fetch('/api/user')
  .then(res => {
    if (!res.ok) throw new Error(`HTTP ${res.status}`);
    return res.json();
  })
  .then(user => fetch(`/api/posts?userId=${user.id}`))
  .then(res => res.json())
  .then(posts => posts.filter(p => p.published))
  .catch(err => {
    console.error('Failed:', err.message);
    return [];
  })
  .finally(() => hideSpinner());

