struct Point { double x; double y; };
double distance(struct Point* a, struct Point* b) {
    double dx = a->x - b->x;
    double dy = a->y - b->y;
    return sqrt(dx*dx + dy*dy);
}

Translate this Go goroutine pattern to equivalent Python asyncio code, preserving the fan-out/fan-in concurrency:
func fetchAll(urls []string) []string {
    ch := make(chan string, len(urls))
    for _, url := range urls {
        go func(u string) {
            resp, _ := http.Get(u)
            body, _ := io.ReadAll(resp.Body)
            ch <- string(body)
        }(url)
    }
    results := make([]string, len(urls))
    for i := range urls {
        results[i] = <-ch
    }
    return results
}
